class Solution:
    def findRotation(self, mat, target):
        # Independent: rotate by building new grids index-by-index four times.
        def rot(g):
            n = len(g)
            return [[g[n - 1 - j][i] for j in range(n)] for i in range(n)]
        cur = [row[:] for row in mat]
        for _ in range(4):
            if cur == target:
                return True
            cur = rot(cur)
        return False

