var findRotation = function(mat, target) {
    const n = mat.length;
    let cur = mat.map(r => r.slice());
    const eq = (a, b) => {
        for (let i = 0; i < n; i++) for (let j = 0; j < n; j++) if (a[i][j] !== b[i][j]) return false;
        return true;
    };
    const rot = (g) => {
        const r = Array.from({length: n}, () => new Array(n));
        for (let i = 0; i < n; i++) for (let j = 0; j < n; j++) r[j][n - 1 - i] = g[i][j];
        return r;
    };
    for (let k = 0; k < 4; k++) {
        if (eq(cur, target)) return true;
        cur = rot(cur);
    }
    return false;
};
